INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6e2f88c7-moex-00296', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於分期付價買賣之敘述，何者正確？', '["分期付價買賣之標的，民法並無限制，故動產、不動產或權利均得為之", "分期付價之買賣，民法規定如買受人解除契約時，出賣人得扣留其所受領價金，惟其扣留之數 額，不得超過標的物全部價金五分之一", "分期付價之買賣，民法規定如出賣人解除契約時，出賣人得扣留其所受領價金，惟其扣留之數 額，不得超過標的物全部價金五分之一", "分期付價之買賣，民法規定如買受人遲付之價額已達全部價金十分之一，出賣人即得請求支付 全部價金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00297', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲購買新電腦一部，而將現用之電腦送給乙。下列敘述，何者正確？', '["甲將電腦所有權移轉乙後，如事後後悔，仍得隨時撤銷契約", "甲在騎機車送電腦給乙的路途中，被酒駕者撞倒，致電腦全毀，甲應負給付不能之責任", "電腦交付後，乙發現有一個USB插孔是故障的，甲有修補的義務", "乙在受領電腦後，因細故跟甲發生爭吵，把甲打到腦震盪，甲得撤銷贈與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00298', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於僱傭契約之敘述，何者錯誤？', '["原則上具有勞務契約專屬性", "經僱用人同意，得使第三人代服勞務", "勞務請求權屬於得讓與之債權", "定有期限之僱傭契約，若當事人之一方遇重大事由時，得於期限屆滿前終止契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00299', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於動產善意取得之敘述，何者正確？', '["動產善意取得之規定，於金錢或未記載權利人之有價證券不適用之", "受讓人於因指示交付而受讓動產之占有，以受讓人受現實交付且交付時為善意者為限，始得主 張善意取得之效果", "受讓人於明知或因抽象輕過失而不知讓與人無讓與動產之權利者，無善意取得之適用", "善意受讓人所取得之動產，如係盜贓物，原占有人自喪失占有時起2年內，雖得請求回復其物， 但惡意占有人則不得請求之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00300', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '抵押物之價值因不可歸責於抵押人之事由致減少者，普通抵押權人得行使何種保全行為？', '["抵押權人於有急迫之情事時，得自為必要之保全處分", "抵押權人得定相當期限，請求抵押人回復抵押物之原狀", "抵押權人得請求抵押人提出與減少價額相當之擔保", "抵押權人僅於抵押人因此所受利益之限度內，得請求提出擔保"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00301', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '關於最高限額抵押權確定之效力，下列敘述，何者錯誤？', '["最高限額抵押權所擔保之原債權確定事由發生後，債務人或抵押人得請求抵押權人結算實際發 生之債權額，並得於未逾原約定最高限額範圍內，就該金額請求變更為普通抵押權之登記", "最高限額抵押權所擔保之原債權確定後，原則上其擔保效力不及於繼續發生之債權或取得之票 據上之權利", "最高限額抵押權所擔保之債權，其請求權已因時效而消滅，如抵押權人於消滅時效完成後，5年 間不實行其抵押權者，其抵押權消滅", "最高限額抵押權所擔保之原債權確定後，於實際債權額超過最高限額時，為債務人設定抵押權 之第三人，於清償最高限額為度之金額後，即得請求塗銷其抵押權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00302', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲以其所有之相鄰土地中之A地為供役不動產、B地為需役不動產，登記設定A地上不得建築高 於兩層樓之建物後，分別將A讓與乙、B讓與丙，並完成移轉登記。就此情形，下列何者正確？', '["甲於A設定之不動產役權有效，但經讓與後，即無拘束乙、丙之效力", "甲於A設定之不動產役權有效，經讓與後，乙為供役不動產所有人、丙為需役不動產所有人", "甲於A設定之不動產役權違反物權法定主義，自始無效", "甲於A設定之不動產役權與A之所有權，因混同而消滅 31570"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00303', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '經營珠寶店之甲因事外出，臨行時指示其僱用之店員乙好好看店。甲外出後，乙管理店內貴重物 品時之身分為何？', '["直接占有人", "占有輔助人", "自主占有人", "準占有人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00304', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '無特別約定時，下列何種標的物為甲、乙所共有？', '["甲利用乙寄放於甲處之螺絲，焊接於修理中之機車", "甲拾得因豪雨淹水漂流至甲處之乙所有之木櫃", "甲於乙所有土地中發現埋藏之金塊", "甲利用乙寄放於甲處之紙張印製而成之書籍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00305', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列關於收養要件之敘述，何者正確？', '["夫妻之一方收養他方之子女時，應長於被收養者 18 歲以上，且經被收養者之親屬會議全體同 意，始生收養之效力", "收養者之年齡，應長於被收養者20歲以上。但夫妻共同收養時，夫妻之一方長於被收養者20 歲以上，而他方僅長於被收養者16歲以上，亦得收養", "直系血親四親等內之親屬成員，得相互收養", "旁系血親在六親等之內且輩分不相當者，得收養為養子女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": "7542e7107b70", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
